// Filtrar mensajes relacionados con diseño gráfico
const messages = $input.all();
const designKeywords = [
  'diseño', 'diseñar', 'logo', 'playera', 'taza', 'poster', 'tarjeta',
  'dibujo', 'imagen', 'arte', 'gráfico', 'vector', 'eps', 'svg',
  'crear', 'hacer', 'generar', 'dragon', 'flor', 'texto', 'letra'
];

const designRequests = messages.filter(msg => {
  const content = msg.body?.toLowerCase() || '';
  return designKeywords.some(keyword => content.includes(keyword));
});

return designRequests.map(msg => ({
  messageId: msg.id,
  from: msg.from,
  body: msg.body,
  timestamp: msg.timestamp,
  type: 'design_request'
}));

// Analizar la solicitud de diseño y extraer parámetros
const requests = $input.all();
const analyzedRequests = [];

for (const request of requests) {
  const body = request.body.toLowerCase();

  // Detectar tipo de producto
  let productType = 'playera';
  if (body.includes('taza') || body.includes('vaso')) productType = 'taza';
  else if (body.includes('poster') || body.includes('cartel')) productType = 'poster';
  else if (body.includes('tarjeta') || body.includes('carta')) productType = 'tarjeta';

  // Detectar estilo
  let style = 'moderno';
  if (body.includes('vintage') || body.includes('retro')) style = 'vintage';
  else if (body.includes('japones') || body.includes('oriental')) style = 'japones';
  else if (body.includes('minimalista') || body.includes('simple')) style = 'minimalista';

  // Detectar colores
  const colors = [];
  if (body.includes('azul')) colors.push('azul');
  if (body.includes('rojo')) colors.push('rojo');
  if (body.includes('verde')) colors.push('verde');
  if (body.includes('negro')) colors.push('negro');
  if (body.includes('blanco')) colors.push('blanco');

  // Detectar elementos
  const elements = [];
  if (body.includes('dragon')) elements.push('dragon');
  if (body.includes('flor')) elements.push('flor');
  if (body.includes('logo')) elements.push('logo');
  if (body.includes('texto')) elements.push('texto');

  analyzedRequests.push({
    ...request,
    analysis: {
      productType,
      style,
      colors: colors.length > 0 ? colors : ['azul'],
      elements: elements.length > 0 ? elements : ['diseño'],
      complexity: body.includes('complejo') || body.includes('detallado') ? 'alta' : 'baja'
    }
  });
}

return analyzedRequests;

// Preparar respuesta para el cliente
const designResult = $input.first();
const originalRequest = $('Analyze Design Request').first();

if (designResult.success) {
  return {
    to: originalRequest.from,
    message: `🎨 ¡Tu diseño está listo!

📋 Detalles:
• Producto: ${originalRequest.analysis.productType}
• Estilo: ${originalRequest.analysis.style}
• Colores: ${originalRequest.analysis.colors.join(', ')}

🔗 Descargar EPS: ${designResult.eps_download_url}
📱 Vista previa: ${designResult.preview_url}

💰 Precio estimado: $${designResult.estimated_price} MXN

⏳ Tiempo de validación: 1-2 horas

¿Te gusta el diseño? Responde con:
✅ SÍ - Para aprobar
❌ NO - Para solicitar cambios
🔄 CAMBIAR - Para modificar`
  };
} else {
  return {
    to: originalRequest.from,
    message: `❌ Lo siento, hubo un problema generando tu diseño.

🔍 Error: ${designResult.error}

💡 Intenta ser más específico, por ejemplo:
"Quiero una playera con un dragón azul estilo japonés"

👨‍💼 O contacta a nuestro equipo: 9671262441`
  };
}

// Registrar la solicitud de diseño en la base de datos
const designRequest = $('Analyze Design Request').first();
const aiResponse = $('Generate Design with AI').first();

const designRecord = {
  user_whatsapp: designRequest.from,
  request_text: designRequest.body,
  product_type: designRequest.analysis.productType,
  style: designRequest.analysis.style,
  colors: designRequest.analysis.colors,
  elements: designRequest.analysis.elements,
  complexity: designRequest.analysis.complexity,
  ai_generated: true,
  status: aiResponse.success ? 'generated' : 'failed',
  eps_file_path: aiResponse.success ? aiResponse.eps_download_url : null,
  preview_url: aiResponse.success ? aiResponse.preview_url : null,
  estimated_price: aiResponse.success ? aiResponse.estimated_price : null,
  error_message: aiResponse.success ? null : aiResponse.error,
  created_at: new Date().toISOString()
};

// Enviar a la base de datos MQN
return designRecord;

// Notificar al equipo técnico sobre nuevo diseño
const designRequest = $('Analyze Design Request').first();
const aiResponse = $('Generate Design with AI').first();

if (aiResponse.success) {
  const notification = {
    to: '9671262441',
    message: `🎨 NUEVO DISEÑO GENERADO POR IA

👤 Cliente: ${designRequest.from}
📋 Solicitud: ${designRequest.body}
🎯 Producto: ${designRequest.analysis.productType}
🎨 Estilo: ${designRequest.analysis.style}
💰 Precio: $${aiResponse.estimated_price} MXN

🔗 EPS: ${aiResponse.eps_download_url}
📱 Preview: ${aiResponse.preview_url}

⏰ Generado: ${new Date().toLocaleString('es-MX')}

✅ Revisar y validar antes de aprobar al cliente`
  };

  return notification;
} else {
  return null;
}

// Respuesta cuando no hay solicitudes de diseño
return {
  message: 'No hay solicitudes de diseño pendientes en este momento.'
};
